// Obtener mensaje de Telegram
const msg = $('Telegram Trigger').item.json.message.text.toLowerCase();
const gistFile = $('Get Current Gist').item.json.files['status.json'];
const data = JSON.parse(gistFile.content);

// Diccionario de IDs de hermandades
const hermaIds = {
  'olivo': '75910',
  'borriquita': '26978',
  'cautivo': '57188',
  'yedra': '68445',
  'expiracion': '1277',
  'sangil': '78066',
  'confalon': '27120',
  'sangre': '64425',
  'mortaja': '88787',
  'piedad': '83972',
  'sanjuan': '47463',
  'silencio': '34963',
  'sinsoga': '77415',
  'soledad': '43437',
  'resucitado': '9329'
};

let response = '';
let pushType = null;
let pushTitle = '';
let pushBody = '';

const parts = msg.split(' ');
const cmd = parts[0];

// Procesar comandos
if (cmd === '/aviso' || cmd === '/peligro' || cmd === '/info') {
  const hermandadName = parts[1];
  const id = hermaIds[hermandadName];

  if (!id) {
    return { json: { 
      skip: true, 
      text: '❌ Hermandad no reconocida. Usa: olivo, borriquita, cautivo, yedra, expiracion, sangil, confalon, sangre, mortaja, piedad, sanjuan, silencio, sinsoga, soledad, resucitado' 
    }};
  }

  const type = cmd === '/peligro' ? 'danger' : (cmd === '/info' ? 'info' : 'warning');
  const title = cmd === '/peligro' ? '🔴 INCIDENCIA GRAVE' : (cmd === '/info' ? 'ℹ️ Información' : '⚠️ Aviso');
  const message = parts.slice(2).join(' ');

  data.alerts[id] = {
    isActive: true,
    type: type,
    title: title,
    message: message,
    timestamp: new Date().toISOString()
  };

  // Configurar push notification
  pushType = type;
  pushTitle = title;
  pushBody = `${hermandadName.toUpperCase()}: ${message}`;

  response = `✅ Alerta publicada para ${hermandadName.toUpperCase()}`;

} else if (cmd === '/ok') {
  const hermandadName = parts[1];
  const id = hermaIds[hermandadName];

  if (id && data.alerts[id]) {
    data.alerts[id].isActive = false;
    response = `✅ Alerta desactivada para ${hermandadName.toUpperCase()}`;
  } else {
    response = '❌ No hay alerta activa para esa hermandad';
  }

} else if (cmd === '/global') {
  const message = parts.slice(1).join(' ');
  data.global = {
    active: true,
    message: message,
    type: 'warning'
  };

  // Push global
  pushType = 'global';
  pushTitle = '🌐 Aviso Global - Semana Santa Écija';
  pushBody = message;

  response = '✅ Aviso Global activado';

} else if (cmd === '/global_ok') {
  data.global.active = false;
  response = '✅ Aviso Global desactivado';

} else {
  return { json: { 
    skip: true, 
    text: 'Comandos disponibles:\n/aviso [hermandad] [mensaje]\n/peligro [hermandad] [mensaje]\n/info [hermandad] [mensaje]\n/ok [hermandad]\n/global [mensaje]\n/global_ok' 
  }};
}

// Actualizar timestamp
data.meta.lastUpdated = new Date().toISOString();

return { 
  json: { 
    body: { 
      files: { 
        'status.json': { 
          content: JSON.stringify(data, null, 2) 
        } 
      } 
    },
    text: response,
    pushType: pushType,
    pushTitle: pushTitle,
    pushBody: pushBody
  }
};

// Determinar qué columna de preferencia filtrar según el tipo de alerta
const pushType = $('Logic Processor').item.json.pushType;

let filterColumn = 'prefs_warning';
if (pushType === 'danger') filterColumn = 'prefs_danger';
else if (pushType === 'info') filterColumn = 'prefs_info';
else if (pushType === 'global') filterColumn = 'prefs_global';

return { json: { filterColumn } };

// Construir mensajes para Expo Push API
// $input.all() devuelve todos los tokens de Supabase
const tokens = $input.all().map(item => item.json.expo_push_token).filter(Boolean);

const pushTitle = $('Logic Processor').item.json.pushTitle;
const pushBody = $('Logic Processor').item.json.pushBody;

if (tokens.length === 0) {
  return { json: { skip: true, tokenCount: 0 } };
}

// Expo Push API acepta hasta 100 mensajes por request
// Dividir en chunks si hay muchos tokens
const chunks = [];
for (let i = 0; i < tokens.length; i += 100) {
  chunks.push(tokens.slice(i, i + 100));
}

const allMessages = chunks.map(chunk => ({
  messages: chunk.map(token => ({
    to: token,
    sound: 'default',
    title: pushTitle,
    body: pushBody,
    priority: 'high',
  }))
}));

// Devolver el primer chunk (para la mayoría de apps será suficiente)
return { json: { messages: allMessages[0].messages, tokenCount: tokens.length } };
